/* Reasoning GP — Articles data (batch 6: B–C topics)
   RCGP/SCA examiner depth. NICE NG12 (May 2025) 2WW pathways stated explicitly where relevant. */
(function(){
  const A = (window.RGP_ARTICLES = window.RGP_ARTICLES || []);
  A.push(

  { id:'bullous-pemphigoid', title:'Bullous pemphigoid', category:'Dermatology', icon:'🫧',
    overview:'A chronic autoimmune sub-epidermal blistering disease, mainly of older adults, in which autoantibodies target the dermo-epidermal junction. It produces tense, often itchy blisters on an urticarial base. It is usually self-limiting over years but can be debilitating, and treatment carries its own risks in frail patients.',
    features:[
      'Tense, fluid-filled blisters on normal or erythematous/urticarial skin, typically on flexures, trunk and limbs; the mouth is usually spared',
      'A prodromal phase of intense itch with urticarial or eczematous plaques may precede blistering by weeks',
      'Predominantly affects people over 70; consider drug triggers (e.g. some gliptins/DPP-4 inhibitors, diuretics)',
      'Blisters are tense and do not rupture easily (Nikolsky sign negative) — in contrast to the fragile blisters of pemphigus',
      'Differential: pemphigus vulgaris (flaccid blisters, mucosal involvement, sicker patient), bullous impetigo, dermatitis herpetiformis, drug eruptions',
      'Diagnosis: skin biopsy for histology and direct immunofluorescence (linear IgG/C3 at the basement membrane); serum BP180/BP230 antibodies'],
    management:[
      'Refer to dermatology to confirm the diagnosis (biopsy + immunofluorescence) and guide treatment',
      'Review the drug list and stop/substitute likely culprit drugs (e.g. DPP-4 inhibitors) where possible',
      'Localised/mild disease: potent topical corticosteroids (e.g. clobetasol) are effective first-line and reduce systemic steroid exposure',
      'More extensive disease: systemic corticosteroids ± steroid-sparing immunosuppressants (e.g. doxycycline, azathioprine, methotrexate), under specialist guidance',
      'Wound and skin care: gentle dressings, emollients, and prevention/treatment of secondary infection',
      'Monitor for the complications of treatment in frail older patients (infection, osteoporosis, glycaemic control, GI effects)',
      'Manage itch and provide supportive nursing care; coordinate with district nursing for extensive disease',
      'Provide patient information and arrange follow-up for relapse'],
    referral:[
      'Suspected bullous pemphigoid → dermatology for biopsy/immunofluorescence and treatment',
      'Widespread blistering, infection, or systemic illness → urgent dermatology/admission',
      'Suspected pemphigus (flaccid blisters, mucosal involvement, unwell) → urgent dermatology',
      'Difficult-to-control disease or treatment complications → specialist review'],
    source:'NICE CKS / BAD bullous pemphigoid guidance' },

  { id:'bunions', title:'Bunions (hallux valgus)', category:'Musculoskeletal', icon:'🦶',
    overview:'A progressive deformity in which the big toe deviates laterally and a bony prominence develops at the first metatarsophalangeal joint. It is common, often familial, and aggravated by footwear. Management is conservative first; surgery is reserved for pain and disability, not appearance.',
    features:[
      'A bony medial prominence at the base of the big toe, with lateral deviation of the hallux and often crowding of the lesser toes',
      'Pain over the prominence (from footwear pressure), the joint, or the lesser toes; bursitis, callus and skin irritation are common',
      'Risk factors: female sex, family history, narrow/high-heeled footwear, hypermobility and inflammatory arthritis',
      'May be associated with secondary deformities (hammer toes, metatarsalgia)',
      'Severity assessed clinically and, where surgery is considered, on weight-bearing X-rays',
      'Consider inflammatory or gouty arthritis if there is a red, hot, acutely painful joint'],
    management:[
      'Reassure and set expectations: conservative measures relieve symptoms but do not reverse the deformity',
      'Footwear advice is central: wide, deep, low-heeled shoes with a roomy toe box',
      'Symptom relief: bunion pads/shields, toe spacers, orthoses for associated foot problems, and simple analgesia/NSAIDs',
      'Podiatry for callus management, orthoses and footwear advice',
      'Surgery (osteotomy) is for persistent pain and functional limitation despite conservative care — not for cosmesis alone',
      'Optimise any underlying inflammatory arthritis',
      'Advise that recurrence is possible after surgery and recovery takes time',
      'Provide written information and review if symptoms progress'],
    referral:[
      'Persistent pain/disability despite conservative measures → orthopaedics/podiatric surgery for consideration of surgery',
      'Suspected inflammatory or gouty arthritis → appropriate work-up/rheumatology',
      'Complex foot deformity or diabetic/neuropathic foot → podiatry/specialist foot service',
      'Skin breakdown/ulceration over the prominence → urgent podiatry (especially in diabetes)'],
    source:'NICE CKS — Bunions (hallux valgus)' },

  { id:'burns-scalds', title:'Burns and scalds', category:'Dermatology', icon:'🔥',
    overview:'Thermal (and chemical/electrical) injuries to the skin, ranging from superficial to full-thickness. Most minor burns are managed in primary care, but recognising the burns that need specialist or emergency care — by depth, size, site, mechanism and patient factors — is critical, as is safeguarding.',
    features:[
      'Superficial (epidermal): red, painful, dry, no blisters (like sunburn) — heals quickly',
      'Superficial partial-thickness: red/pink, painful, blistered, moist, blanches — heals in ~2–3 weeks',
      'Deep partial-thickness: blotchy red/white, less painful, may blister — slower healing, scarring risk',
      'Full-thickness: white/brown/black, dry, leathery, painless (nerves destroyed) — needs surgery',
      'Estimate the area (e.g. the patient’s palm ≈ 1% TBSA; rule of nines in adults) and assess depth, site and mechanism',
      'RED FLAGS: airway/inhalation injury (facial burns, soot, hoarseness, stridor), circumferential burns, electrical/chemical burns, and burns to face/hands/feet/perineum/major joints'],
    management:[
      'First aid: stop the burning, remove clothing/jewellery, and cool with running cool (not ice-cold) water for 20 minutes (effective up to ~3 hours); keep the patient warm',
      'Cover with cling film (longitudinally, not circumferentially) or a clean non-adherent dressing; provide adequate analgesia',
      'Do not de-roof small blisters routinely; manage larger/at-risk blisters per local guidance; do not apply creams before assessment',
      'Dress superficial partial-thickness burns with non-adherent/hydrocolloid dressings and review for healing and infection',
      'Check tetanus status and update as needed; treat infection if it develops (it is not routine prophylaxis)',
      'Chemical burns: brush off dry agents, irrigate copiously with water, and seek specialist/toxbase advice; electrical burns need ECG and assessment for deep injury',
      'Refer per national burn-referral criteria (depth, size, site, mechanism, age, comorbidity) and arrange emergency care for airway/large burns',
      'Always consider non-accidental injury in children and vulnerable adults (e.g. clear-edged immersion scalds, inconsistent history) and act on safeguarding concerns'],
    referral:[
      'Inhalation/airway injury, large burns (e.g. >2–3% in children, >3% in adults), full-thickness, circumferential, or high-voltage electrical burns → emergency department/burns unit',
      'Burns to the face, hands, feet, perineum, genitalia, or over major joints; chemical burns; or non-healing burns → specialist burns service',
      'Suspected non-accidental injury → safeguarding procedures',
      'Signs of infection or systemic sepsis → urgent assessment'],
    source:'NICE CKS / National Burn Care referral guidance' },

  { id:'bursitis', title:'Bursitis', category:'Musculoskeletal', icon:'🦵',
    overview:'Inflammation of a bursa — the fluid-filled sacs that cushion tendons and bones — commonly at the elbow (olecranon), knee (prepatellar), shoulder (subacromial), hip (trochanteric) and ankle. Most is from friction/overuse or pressure; the crucial differential is septic bursitis, which needs prompt treatment.',
    features:[
      'Localised swelling, tenderness and sometimes warmth over the affected bursa, with pain on movement/pressure',
      'Olecranon ("student’s elbow") and prepatellar ("housemaid’s knee") bursitis follow repetitive pressure/kneeling/leaning',
      'Trochanteric (greater trochanteric pain syndrome) causes lateral hip pain, worse lying on that side and on activity',
      'SEPTIC bursitis: marked warmth, redness, severe tenderness, fever, and often a skin breach/cellulitis — most common at the olecranon and prepatellar bursae',
      'Consider gout/inflammatory arthritis and rheumatoid nodules as causes/mimics',
      'Diagnosis is usually clinical; aspirate if infection or crystal arthropathy is suspected'],
    management:[
      'Identify and reduce the precipitant: avoid pressure/kneeling/leaning, use padding, and modify activity',
      'Conservative care: rest, ice, compression, elevation, and simple analgesia/NSAIDs',
      'Aspiration can relieve a tense bursa and provides fluid for analysis where infection/crystals are suspected',
      'Corticosteroid injection may help persistent non-infective bursitis (e.g. trochanteric) — never inject if infection is possible',
      'For septic bursitis: aspirate/send fluid, start antibiotics (covering S. aureus) and arrange close review or admission if systemically unwell',
      'Physiotherapy and a graded return to activity for chronic/overuse bursitis (e.g. subacromial, trochanteric)',
      'Address contributory factors (occupational kneeling, gout, inflammatory arthritis)',
      'Safety-net for spreading infection or systemic illness'],
    referral:[
      'Septic bursitis with systemic illness, spreading cellulitis, or failure to respond to oral antibiotics → urgent assessment/admission',
      'Recurrent or refractory bursitis → orthopaedics/MSK (consider bursectomy)',
      'Suspected underlying inflammatory arthritis/gout → rheumatology',
      'Diagnostic uncertainty (e.g. possible septic arthritis) → urgent assessment'],
    source:'NICE CKS — Bursitis' },

  { id:'carbon-monoxide', title:'Carbon monoxide poisoning', category:'General', icon:'☠️',
    overview:'Poisoning from inhaling carbon monoxide — a colourless, odourless gas produced by faulty fuel-burning appliances, blocked flues, and fires. It binds haemoglobin with high affinity, causing tissue hypoxia. It is easily missed because symptoms are non-specific and "flu-like"; the diagnosis hinges on environmental clues.',
    features:[
      'Non-specific symptoms: headache (the commonest), dizziness, nausea/vomiting, fatigue, confusion and breathlessness',
      'KEY clues to suspect CO: symptoms improve when away from home/work and recur on return; other household members or pets affected; faulty boiler, blocked flue, or fumes; symptoms worse in winter when heating is used',
      'Severe poisoning: drowsiness, seizures, loss of consciousness, arrhythmia, and cardiac/neurological injury',
      'Classic "cherry-red" skin and false-normal pulse oximetry (standard oximeters cannot distinguish carboxyhaemoglobin) are unreliable/late signs',
      'Diagnosis: a raised carboxyhaemoglobin (COHb) level on blood gas/CO-oximetry (note smokers have a higher baseline) and the clinical/environmental picture',
      'Delayed neuropsychiatric sequelae (memory, mood, movement disorders) can follow significant poisoning'],
    management:[
      'Maintain a high index of suspicion — ask directly about appliances, household clusters, and symptom patterns (the COMA questions: Cohabitees/Co-occupants, Outdoor improvement, Maintenance of appliances, Alarm)',
      'Remove the patient from the source immediately and give high-flow 100% oxygen via a non-rebreather mask as soon as possible',
      'Arrange urgent hospital assessment for measurement of COHb and treatment; oxygen shortens CO half-life dramatically',
      'Assess for end-organ effects (ECG, cardiac, neurological) and treat accordingly',
      'Consider hyperbaric oxygen referral for severe poisoning (e.g. loss of consciousness, neurological signs, pregnancy, significant cardiac involvement) — discuss with toxicology/NPIS',
      'Address the source: advise not to return until appliances are checked, arrange Gas Safe inspection, and ensure a CO alarm is fitted',
      'Protect other occupants — the whole household may need assessment',
      'Provide follow-up for delayed neuropsychiatric effects'],
    referral:[
      'Suspected significant CO poisoning → emergency hospital assessment with high-flow oxygen en route',
      'Loss of consciousness, neurological signs, cardiac involvement, or pregnancy → urgent toxicology input ± hyperbaric oxygen',
      'Household exposure → ensure all occupants are assessed and the source made safe',
      'Persisting neuropsychiatric symptoms → appropriate follow-up'],
    source:'NICE CKS / NPIS (TOXBASE) guidance' },

  { id:'cardiomyopathy', title:'Cardiomyopathy', category:'Cardiovascular & Renal', icon:'🫀',
    overview:'A heterogeneous group of diseases of the heart muscle — dilated, hypertrophic, restrictive and arrhythmogenic — causing heart failure, arrhythmia and sudden cardiac death. Hypertrophic cardiomyopathy is the commonest cause of sudden cardiac death in young people, so recognition and family screening matter.',
    features:[
      'Dilated (DCM): heart failure symptoms (breathlessness, oedema, fatigue), arrhythmia, and thromboembolism; causes include genetic, alcohol, viral, peripartum and toxins',
      'Hypertrophic (HCM): often asymptomatic; exertional breathlessness, chest pain, palpitations, syncope (especially on exertion); risk of sudden death; an ejection systolic murmur worsened by Valsalva',
      'Restrictive: features of right and left heart failure with preserved systolic function; causes include amyloidosis and other infiltrative diseases',
      'Arrhythmogenic (ARVC): ventricular arrhythmias and sudden death, often in young athletes',
      'RED FLAGS: exertional syncope, a family history of sudden cardiac death or cardiomyopathy, and unexplained heart failure in a younger patient',
      'Diagnosis: ECG, echocardiography (cornerstone), cardiac MRI, ambulatory monitoring, and genetic testing'],
    management:[
      'Investigate suspected cardiomyopathy with ECG and echocardiography, and refer to cardiology/inherited-cardiac-conditions services',
      'Take a careful family history of sudden cardiac death and cardiomyopathy; arrange family screening (ECG/echo ± genetics)',
      'Manage heart failure per guidelines where present (e.g. ACEi/ARB or ARNI, beta-blocker, MRA, SGLT2 inhibitor) under specialist guidance — but avoid agents that worsen outflow obstruction in HCM',
      'In HCM, advise on activity (avoid intense competitive/strenuous exertion as advised), treat symptoms (beta-blockers/verapamil), and assess sudden-death risk for ICD',
      'Address reversible causes: alcohol cessation in alcoholic DCM, treat the underlying disease in restrictive/infiltrative forms (e.g. amyloid)',
      'Anticoagulate where indicated (e.g. AF, intracardiac thrombus); manage arrhythmias',
      'Provide clear advice to seek urgent help for exertional syncope, severe palpitations, or worsening heart failure',
      'Support patients and families, including genetic counselling and psychological impact'],
    referral:[
      'Suspected cardiomyopathy (abnormal ECG/echo, unexplained heart failure, concerning murmur) → cardiology',
      'Exertional syncope, family history of sudden cardiac death, or high arrhythmic risk → urgent cardiology / inherited-cardiac-conditions service (ICD assessment)',
      'First-degree relatives of affected patients → family cardiac screening',
      'Acute decompensated heart failure or sustained arrhythmia → emergency admission'],
    source:'NICE CKS / ESC cardiomyopathy guidance' },

  { id:'carpal-tunnel', title:'Carpal tunnel syndrome', category:'Musculoskeletal', icon:'✋',
    overview:'Compression of the median nerve at the wrist — the commonest entrapment neuropathy. It causes characteristic hand paraesthesia and, if untreated, thenar weakness and wasting. Most is idiopathic, but identifying secondary causes (pregnancy, hypothyroidism, diabetes) guides management.',
    features:[
      'Numbness, tingling and pain in the median nerve distribution (thumb, index, middle and radial half of ring finger), classically worse at night and waking the patient, who shakes the hand for relief',
      'Symptoms provoked by activities holding the wrist flexed (phone, driving, reading)',
      'Positive Tinel’s (tapping) and Phalen’s (wrist flexion) tests; later, thenar weakness and wasting (abductor pollicis brevis)',
      'Secondary causes: pregnancy, hypothyroidism, diabetes, rheumatoid arthritis, obesity, acromegaly, and repetitive wrist use',
      'Often bilateral; consider amyloidosis if bilateral CTS occurs with cardiac/other features',
      'Diagnosis is clinical; nerve conduction studies confirm and grade severity when surgery or diagnosis is uncertain'],
    management:[
      'Confirm clinically and look for/treat secondary causes (check TFTs, glucose/HbA1c; consider pregnancy)',
      'Mild–moderate: a wrist splint worn at night (neutral position) is effective first-line; modify provoking activities',
      'A corticosteroid injection into the carpal tunnel gives good short–medium-term relief and can be diagnostic',
      'In pregnancy, reassure that symptoms usually resolve after delivery and manage conservatively (splints)',
      'Arrange nerve conduction studies where the diagnosis is uncertain or surgery is being considered',
      'Refer for carpal tunnel decompression surgery if there are persistent/severe symptoms, motor signs (weakness/wasting), or failure of conservative treatment',
      'Surgery is definitive and highly effective; advise on recovery and that established wasting may not fully recover',
      'Provide written information and review response to conservative measures'],
    referral:[
      'Persistent/severe symptoms, thenar weakness or wasting, or failure of conservative treatment → hand surgery/orthopaedics for decompression',
      'Diagnostic uncertainty → nerve conduction studies / neurology',
      'Suspected underlying systemic cause needing specialist input (e.g. amyloidosis, acromegaly) → relevant specialty',
      'Acute severe or rapidly progressive deficit → urgent assessment'],
    source:'NICE CKS — Carpal tunnel syndrome' },

  { id:'cataracts', title:'Cataracts in adults', category:'Ophthalmology', icon:'👁️',
    overview:'Progressive clouding of the lens causing painless visual decline — the leading cause of reversible blindness worldwide. It is largely age-related, and modern day-case surgery is highly effective. The primary-care role is recognition, addressing reversible contributors, and timely referral based on functional impact.',
    features:[
      'Gradual, painless blurring of vision, glare/haloes around lights (especially night driving), faded colours and reduced contrast',
      'Frequent changes in glasses prescription; second sight (transient near-vision improvement) in some',
      'A reduced red reflex and visible lens opacity on examination',
      'Risk factors: ageing, diabetes, corticosteroid use, smoking, UV exposure, ocular trauma and previous eye surgery',
      'In children/young people, consider congenital/secondary causes (an absent red reflex in a baby is an emergency)',
      'Diagnosis is clinical/optometric; the impact on the patient’s daily function and goals guides timing of surgery'],
    management:[
      'Confirm via optometry; refer based on the functional impact on the patient’s life (reading, driving, work, falls) and their wishes — not a fixed acuity threshold',
      'Optimise modifiable factors: update glasses, improve lighting, manage glare; support smoking cessation and good diabetic control',
      'Address driving: advise the patient of the visual standards for driving and the duty to meet/notify the DVLA if vision falls below standard',
      'Explain that cataract surgery (phacoemulsification with intraocular lens) is a safe, effective day-case procedure',
      'Review medications contributing to cataract (e.g. long-term corticosteroids) where clinically appropriate',
      'Manage falls risk in older patients with significant visual impairment',
      'Provide realistic expectations and information about surgery and its small risks',
      'Arrange optometric review and re-refer if vision deteriorates'],
    referral:[
      'Visually significant cataract affecting daily function → routine ophthalmology referral for surgery',
      'Absent/white red reflex in a child → urgent ophthalmology (congenital cataract; exclude retinoblastoma — NICE NG12)',
      'Rapidly progressive cataract, or cataract with other eye disease (e.g. diabetic retinopathy, glaucoma) → ophthalmology',
      'Sudden visual loss → same-day ophthalmology (a different pathology)'],
    source:'NICE NG77 (Cataracts in adults)' },

  { id:'cellulitis', title:'Cellulitis', category:'Dermatology', icon:'🦠',
    overview:'An acute bacterial infection of the dermis and subcutaneous tissue, usually streptococcal or staphylococcal, presenting as a spreading area of warm, red, tender skin — most often on the lower leg. The priorities are confirming the diagnosis (it is over-diagnosed), excluding mimics, and recognising severe/necrotising infection.',
    features:[
      'A poorly demarcated area of erythema, warmth, swelling and tenderness, usually unilateral and most often on the lower leg',
      'May have systemic features (fever, malaise) and a portal of entry (break in the skin, tinea pedis, leg ulcer, lymphoedema)',
      'Lymphangitis (red streaking) and tender regional lymphadenopathy may occur',
      'Bilateral lower-leg "cellulitis" is rare — consider venous eczema/stasis, lipodermatosclerosis, or contact dermatitis instead (the commonest mimics)',
      'RED FLAGS for necrotising fasciitis: pain out of proportion, rapidly spreading, dusky/purple/black skin, blistering, crepitus, and systemic toxicity',
      'Assess severity (e.g. Eron classification) and look for sepsis; mark the erythema margin to track progression'],
    management:[
      'Confirm the diagnosis and actively consider mimics (especially venous eczema and lipodermatosclerosis in bilateral or chronic cases)',
      'Treat with oral antibiotics first-line (e.g. flucloxacillin; clarithromycin/doxycycline if penicillin-allergic) per local guidance and site (e.g. near eyes/nose, after bites)',
      'Mark and date the erythema border, elevate the limb, treat pain, and ensure good hydration',
      'Treat the portal of entry (e.g. antifungal for tinea pedis, emollients, ulcer/lymphoedema care) to prevent recurrence',
      'Manage oedema and underlying lymphoedema/venous disease — key to preventing recurrent cellulitis',
      'Arrange review within 48 hours (or sooner) and safety-net for spreading infection or systemic deterioration',
      'Admit for IV antibiotics if severe, systemically unwell, rapidly progressing, immunocompromised, or failing oral therapy',
      'Consider antibiotic prophylaxis for recurrent cellulitis after addressing reversible factors'],
    referral:[
      'Suspected necrotising fasciitis (pain out of proportion, rapid spread, dusky skin, crepitus, sepsis) → immediate surgical emergency referral',
      'Severe cellulitis, sepsis, immunocompromise, facial/orbital or hand involvement, or failure of oral antibiotics → hospital admission for IV therapy',
      'Periorbital/orbital cellulitis → urgent same-day ophthalmology/ENT assessment',
      'Recurrent cellulitis → review and manage underlying causes ± prophylaxis'],
    source:'NICE NG141 (Cellulitis — antimicrobial prescribing)' },

  { id:'cerebral-palsy', title:'Cerebral palsy', category:'Paediatrics', icon:'👶',
    overview:'A group of permanent disorders of movement and posture caused by a non-progressive insult to the developing brain (antenatal, perinatal or early postnatal). Although the brain lesion is static, its clinical effects evolve as the child grows. Care is multidisciplinary and lifelong; the GP supports the child, family and associated health needs.',
    features:[
      'Motor types: spastic (commonest), dyskinetic, ataxic, or mixed; distribution may be hemiplegic, diplegic or quadriplegic',
      'Early clues: delayed motor milestones, abnormal tone (hypertonia or hypotonia), persistent primitive reflexes, asymmetry of movement, feeding difficulties, and abnormal posture',
      'Associated impairments are common: learning disability, epilepsy, visual and hearing problems, speech/communication difficulty, and feeding/GI and respiratory problems',
      'Risk factors: prematurity, low birth weight, hypoxic-ischaemic encephalopathy, intrauterine infection, kernicterus, and neonatal stroke',
      'Function is described using validated systems (e.g. the Gross Motor Function Classification System, GMFCS)',
      'A diagnosis is clinical, supported by neuroimaging; the underlying lesion is non-progressive — deterioration warrants re-evaluation'],
    management:[
      'Coordinate care through a multidisciplinary team (paediatrics, physiotherapy, occupational therapy, speech and language therapy, orthopaedics, dietetics, social care and education)',
      'Manage spasticity with physiotherapy, orthoses, and (specialist-led) oral agents, botulinum toxin, intrathecal baclofen or orthopaedic surgery',
      'Actively screen for and manage associated problems: epilepsy, feeding/nutrition (consider gastrostomy), constipation, drooling, hip surveillance, pain, sleep and respiratory issues',
      'Support communication and mobility with appropriate aids and assistive technology',
      'Optimise the child’s participation in education and daily life; support transition to adult services',
      'Support families: respite, carer wellbeing, benefits, and education/social-care liaison',
      'In primary care, provide accessible reviews, immunisations, and be alert to diagnostic overshadowing (do not attribute new symptoms to CP without assessment)',
      'Provide proactive care planning, including for the more severely affected and at end of life where relevant'],
    referral:[
      'Suspected cerebral palsy or motor delay → community paediatrics / child development service',
      'Spasticity management → specialist (neurology, orthopaedics, physiotherapy)',
      'Associated conditions → relevant services (epilepsy, ophthalmology, audiology, dietetics, orthopaedics for hip surveillance)',
      'Progressive deterioration or loss of skills → re-evaluate (CP is non-progressive — consider an alternative diagnosis)'],
    source:'NICE NG62 (Cerebral palsy in under 25s) / NG119 (management)' },

  { id:'cervical-cancer', title:'Cervical cancer', category:'Women’s health', icon:'🎗️',
    overview:'A largely preventable cancer caused by persistent high-risk HPV infection, prevented by vaccination and screening and curable when caught early. The primary-care role is promoting prevention and screening, and recognising the symptoms — especially abnormal bleeding — that mandate urgent referral.',
    features:[
      'Abnormal vaginal bleeding is the cardinal symptom: post-coital bleeding, intermenstrual bleeding, or postmenopausal bleeding',
      'Other features: persistent vaginal discharge (sometimes blood-stained/offensive), pelvic pain, and dyspareunia',
      'Advanced disease: weight loss, leg swelling, urinary/bowel symptoms, and renal impairment from ureteric obstruction',
      'An abnormal-looking cervix (mass, ulceration, contact bleeding) on speculum examination is a red flag regardless of screening history',
      'Risk factors: persistent high-risk HPV, smoking, immunosuppression (including HIV), early/multiple sexual partners, and non-attendance at screening',
      'Prevention: HPV vaccination and the NHS Cervical Screening Programme (HPV-primary testing with cytology triage)'],
    management:[
      'Promote HPV vaccination (offered in school) and encourage uptake of cervical screening at the recommended intervals',
      'Take any abnormal bleeding seriously — examine the cervix; an abnormal appearance needs urgent referral regardless of a recent normal smear (screening does not exclude symptomatic cancer)',
      'Manage screening results per programme protocols (HPV-negative → routine recall; HPV-positive with abnormal cytology → colposcopy)',
      'Refer abnormal/suspicious bleeding and abnormal cervical appearance promptly on the suspected-cancer pathway',
      'Support smoking cessation and ensure screening for immunosuppressed/HIV-positive women is up to date',
      'Provide information and psychological support; coordinate with gynae-oncology for confirmed cancer',
      'Address fertility and treatment-related concerns sensitively',
      'Ensure women who do not attend screening are encouraged and supported to do so'],
    referral:[
      'Clinical appearance of the cervix consistent with cervical cancer → urgent 2WW gynae-oncology referral (NICE NG12) — do not wait for screening',
      'Unexplained postmenopausal, post-coital or persistent intermenstrual bleeding → assess and refer per the suspected-cancer pathway',
      'Abnormal screening results → colposcopy via the screening programme',
      'Confirmed cancer → gynae-oncology MDT'],
    source:'NICE NG12 / NHS Cervical Screening Programme' },

  { id:'cmt', title:'Charcot-Marie-Tooth disease', category:'Neurology', icon:'🧠',
    overview:'The commonest inherited peripheral neuropathy — a group of genetic disorders affecting the peripheral nerves, causing slowly progressive distal motor and sensory loss. It is not life-limiting in most forms, and management is supportive and multidisciplinary, with an emphasis on function and avoiding nerve-toxic drugs.',
    features:[
      'Slowly progressive, length-dependent weakness and wasting — distal legs first ("inverted champagne bottle" calves), then hands',
      'Foot deformity: high arches (pes cavus) and hammer toes; frequent ankle sprains, tripping and foot drop',
      'Distal sensory loss and reduced/absent ankle reflexes; usually painless, though some have neuropathic pain',
      'Onset often in childhood/adolescence; a family history is common (usually autosomal-dominant, e.g. CMT1A from PMP22 duplication)',
      'Function is preserved for many years; respiratory and severe disability are uncommon in typical forms',
      'Diagnosis: nerve conduction studies (demyelinating vs axonal) and genetic testing; specialist confirmation'],
    management:[
      'Refer to neurology for diagnosis (nerve conduction studies, genetics) and to a specialist neuromuscular service',
      'Management is supportive and multidisciplinary: physiotherapy, occupational therapy, orthotics (ankle-foot orthoses), and podiatry for foot care',
      'Orthopaedic input for disabling foot deformity (e.g. tendon transfer, corrective surgery)',
      'Manage neuropathic pain where present (e.g. amitriptyline, gabapentin/pregabalin, duloxetine)',
      'Crucially, avoid neurotoxic drugs that can worsen the neuropathy — notably vincristine (contraindicated) and other potentially neurotoxic agents; review carefully before prescribing',
      'Encourage exercise within tolerance, maintain mobility, and provide aids/adaptations and falls prevention',
      'Offer genetic counselling and discuss inheritance and family implications',
      'Support employment, mobility and psychological wellbeing, and arrange regular review'],
    referral:[
      'Suspected inherited neuropathy → neurology / neuromuscular service',
      'Disabling foot deformity or contractures → orthopaedics/podiatry',
      'Significant neuropathic pain or functional decline → relevant specialist/therapy services',
      'Family planning/inheritance questions → clinical genetics'],
    source:'NICE CKS / neuromuscular specialist guidance' },

  { id:'charles-bonnet', title:'Charles Bonnet syndrome', category:'Ophthalmology', icon:'👁️',
    overview:'Complex visual hallucinations occurring in people with significant visual impairment, in the absence of psychiatric or cognitive disease and with full insight that the images are not real. It is common, under-recognised and benign, but distressing — and patients often fear they are "going mad", so explanation and reassurance are therapeutic.',
    features:[
      'Vivid, complex, purely visual hallucinations (people, faces, animals, patterns, buildings) in someone with reduced vision',
      'Crucially, the person retains insight that the images are not real, and there are no hallucinations in other senses',
      'No psychiatric illness, delusions, or cognitive impairment to explain the hallucinations',
      'Common with macular degeneration, glaucoma, diabetic retinopathy, cataract and other causes of visual loss; commoner in older people',
      'Hallucinations may be more frequent in low light, with inactivity, or at times of stress/isolation',
      'Differential: psychotic disorders (loss of insight, other modalities, delusions), delirium, dementia with Lewy bodies, and drug effects'],
    management:[
      'Recognise the syndrome and explain it clearly — that it results from the brain’s response to reduced visual input, is not a mental illness, and does not mean dementia: this reassurance is the most important intervention',
      'Validate the experience; many patients are greatly relieved simply to have it named and explained',
      'Optimise vision: ensure refraction is up to date, treat reversible eye disease (e.g. cataract), and improve lighting',
      'Practical strategies during episodes: changing lighting, blinking or moving the eyes, altering activity, and increasing social/sensory stimulation',
      'Address isolation and low mood, which can worsen the experience; provide support and signpost sight-loss services (e.g. RNIB)',
      'Review medications that might contribute and exclude delirium/cognitive causes if the picture is atypical',
      'Reassure about the usually self-limiting/fluctuating course, while acknowledging it can persist',
      'Refer if there is diagnostic doubt or significant distress'],
    referral:[
      'Diagnostic uncertainty, loss of insight, hallucinations in other senses, or features of psychosis/delirium/dementia → relevant assessment (psychiatry/older-adult services)',
      'Treatable eye disease → ophthalmology/optometry to optimise vision',
      'Significant distress or low mood → psychological support / mental-health services',
      'Sight-loss support → low-vision and voluntary services'],
    source:'NICE CKS / Royal College of Ophthalmologists guidance' },

  { id:'chest-infection', title:'Chest infection (lower respiratory tract infection)', category:'Respiratory', icon:'🫁',
    overview:'An umbrella term covering acute bronchitis and community-acquired pneumonia. The central skills are distinguishing self-limiting viral illness from pneumonia, using severity scoring to decide on antibiotics and admission, and recognising the cough that needs imaging for cancer.',
    features:[
      'Cough (often productive), breathlessness, fever, chest discomfort and malaise',
      'PNEUMONIA features: focal chest signs (bronchial breathing, crackles, dullness), high fever, tachypnoea, tachycardia, hypoxia and feeling very unwell',
      'Use CRB-65 in the community (Confusion, Respiratory rate ≥30, BP <90/≤60, age ≥65) to assess severity and need for admission',
      'Most acute bronchitis is viral and self-limiting; pneumonia is more likely to need antibiotics and sometimes admission',
      'Higher-risk groups: older, frail, comorbid (COPD, heart failure, diabetes), and immunosuppressed patients',
      'A cough persisting >3 weeks, haemoptysis, or weight loss warrants a chest X-ray (lung cancer consideration)'],
    management:[
      'Assess severity (CRB-65) and decide management/admission accordingly',
      'Acute bronchitis: usually no antibiotics; self-care and safety-netting, with a back-up prescription only if appropriate',
      'Community-acquired pneumonia: start antibiotics promptly per local/NICE guidance, guided by severity (e.g. amoxicillin for low-severity; add a macrolide or use alternatives for higher severity/penicillin allergy)',
      'Advise on fluids, antipyretics/analgesia and rest; review and safety-net for deterioration',
      'Arrange admission for high CRB-65, hypoxia, sepsis, inability to cope at home, or significant comorbidity',
      'Arrange a chest X-ray and follow-up for pneumonia, particularly to confirm resolution in older patients/smokers',
      'Image (CXR) for any cough >3 weeks or red-flag features to exclude malignancy',
      'Reinforce smoking cessation and ensure relevant vaccinations (influenza, pneumococcal, COVID-19)'],
    referral:[
      'High CRB-65, hypoxia, sepsis, or inability to manage at home → hospital admission',
      'Cough ≥3 weeks unexplained, haemoptysis, or weight loss (especially smoker/ex-smoker ≥40) → urgent chest X-ray and 2WW suspected lung-cancer pathway if indicated (NICE NG12)',
      'Failure to improve, recurrent infection, or non-resolving CXR changes → respiratory',
      'Underlying chronic lung disease needing optimisation → respiratory review'],
    source:'NICE NG138/NG191 (pneumonia) / NG120 (cough) / NICE NG12' },

  { id:'chiari', title:'Chiari malformation', category:'Neurology', icon:'🧠',
    overview:'A structural defect in which part of the cerebellum (the tonsils) herniates through the foramen magnum. Chiari I — the type usually seen in adults — is often an incidental finding, but can cause characteristic cough-related headache and, importantly, a syrinx (syringomyelia) with progressive neurological damage.',
    features:[
      'Classic symptom: an occipital/sub-occipital headache provoked by coughing, sneezing, straining or Valsalva (typically brief)',
      'Other features: neck pain, dizziness/imbalance, visual disturbance, tinnitus, and dysphagia',
      'Syringomyelia (a fluid cavity in the cord) may develop: "cape" distribution dissociated sensory loss (loss of pain/temperature with preserved touch), wasting/weakness of the hands, and scoliosis',
      'Lower cranial nerve and brainstem signs in more significant cases',
      'Chiari I is often found incidentally on MRI done for other reasons',
      'Diagnosis is by MRI of the brain and cervical spine (to detect tonsillar descent and any syrinx)'],
    management:[
      'Distinguish symptomatic from incidental Chiari — many incidental findings need only explanation and reassurance',
      'Arrange MRI of the brain and whole spine where symptomatic, to confirm and to look for a syrinx',
      'Refer symptomatic patients (especially with a cough headache, neurological signs, or a syrinx) to neurosurgery',
      'Symptomatic management of headache; avoid attributing red-flag neurology to a "benign" malformation without assessment',
      'Surgical decompression (posterior fossa decompression) is offered for significant symptoms or a progressive syrinx',
      'Monitor for progression of neurological signs in those managed conservatively',
      'Provide patient information and clear safety-netting for new/worsening neurology',
      'Address associated conditions (e.g. hydrocephalus) as identified'],
    referral:[
      'Symptomatic Chiari (cough headache, neurological signs) or any syrinx → neurosurgery',
      'Progressive neurological deficit → urgent neurosurgical assessment',
      'Diagnostic uncertainty / incidental finding with atypical symptoms → neurology',
      'Associated hydrocephalus or acute deterioration → emergency referral'],
    source:'NICE CKS / neurosurgical guidance' },

  { id:'chickenpox', title:'Chickenpox (varicella)', category:'Infectious diseases', icon:'🦠',
    overview:'A highly contagious primary infection with varicella-zoster virus, usually a mild self-limiting illness in healthy children. It matters most in higher-risk groups — neonates, pregnant women, and the immunocompromised — where it can cause severe disease, and because of its complications.',
    features:[
      'A prodrome of fever/malaise, then an itchy vesicular rash appearing in crops — macule → papule → vesicle → crust — with lesions at different stages',
      'Rash typically starts on the face/trunk and spreads; lesions in the mouth and on mucosae can occur',
      'Infectious from ~48 hours before the rash until all lesions have crusted (usually ~5 days after onset)',
      'Complications: secondary bacterial skin infection, pneumonia, cerebellitis/encephalitis, and (rarely) severe disseminated disease',
      'HIGH-RISK groups: neonates, pregnant women (risk of severe varicella, varicella pneumonia, and — if early pregnancy — fetal varicella syndrome), and the immunocompromised',
      'Shingles (herpes zoster) is reactivation of the same virus later in life'],
    management:[
      'Healthy children: supportive care — paracetamol for fever (avoid ibuprofen, which is associated with skin complications), antihistamine/emollients for itch, hydration, and keep nails short',
      'Advise on infectivity and exclusion: stay away from school/nursery and avoid contact with high-risk individuals until all lesions have crusted',
      'Consider antiviral treatment (aciclovir) for adolescents/adults presenting within 24 hours of rash onset, and for those at higher risk of complications',
      'Assess and act promptly in high-risk groups: pregnant women, neonates and the immunocompromised need urgent specialist advice',
      'Post-exposure: non-immune pregnant women or immunocompromised contacts need urgent assessment for antibodies and possible varicella prophylaxis (immunoglobulin/antivirals)',
      'Safety-net for complications: high or persistent fever, breathlessness, drowsiness/neurological signs, or spreading/painful skin infection',
      'Treat secondary bacterial infection with antibiotics if it develops',
      'Provide written information on course, infectivity and red flags'],
    referral:[
      'Chickenpox (or significant exposure) in a pregnant woman, neonate, or immunocompromised patient → urgent specialist advice (obstetrics/paediatrics/ID) for assessment ± prophylaxis/antivirals',
      'Complications (pneumonia, encephalitis/cerebellitis, severe secondary infection, dehydration) → emergency admission',
      'Severe or atypical disease → infectious diseases',
      'Neonatal varicella → urgent paediatric/neonatal assessment'],
    source:'NICE CKS / Green Book (varicella)' },

  { id:'chilblains', title:'Chilblains (pernio)', category:'Dermatology', icon:'❄️',
    overview:'An abnormal inflammatory skin reaction to cold (but non-freezing) exposure, causing itchy, painful, red-purple lesions on the extremities. They are common and benign, usually resolving spontaneously; the main task is reassurance, prevention, and recognising when an underlying condition is driving recurrent or atypical disease.',
    features:[
      'Itchy or burning red-purple papules/plaques on the toes, fingers, and sometimes ears/nose, developing hours after cold exposure',
      'Lesions may blister or ulcerate in severe cases; they typically settle over 1–3 weeks',
      'Triggered by cold, damp conditions; commoner in young women, those with poor peripheral circulation, and low body weight',
      'Recurrent/atypical chilblains, or onset out of context, may point to an underlying cause: connective-tissue disease (e.g. lupus — "chilblain lupus"), Raynaud’s, or a haematological cause',
      'Chilblain-like lesions were noted in association with viral infection (e.g. COVID-19)',
      'Diagnosis is clinical; investigate for an underlying cause only where the picture is atypical/persistent'],
    management:[
      'Reassure: most chilblains are benign and resolve with conservative measures',
      'Prevention is the mainstay: keep the whole body, hands and feet warm and dry; warm extremities gradually (avoid direct heat); wear warm, non-constrictive footwear/gloves; and stop smoking',
      'Symptom relief: emollients, and a topical corticosteroid for itch/inflammation in troublesome lesions',
      'Avoid rapid rewarming and scratching (which can lead to ulceration/infection)',
      'For recurrent/severe chilblains, nifedipine can be considered to improve peripheral circulation',
      'Treat any secondary infection of ulcerated lesions',
      'Investigate for an underlying cause (e.g. autoimmune screen) if lesions are atypical, persistent, ulcerating, or occur without clear cold exposure',
      'Provide written advice on prevention and review if not settling'],
    referral:[
      'Atypical, persistent, ulcerating or recurrent chilblains, or features suggesting connective-tissue disease → dermatology/rheumatology',
      'Severe ulceration or secondary infection not responding → dermatology',
      'Suspected underlying systemic disease → relevant specialist',
      'Significant peripheral vascular disease → vascular assessment'],
    source:'NICE CKS — Chilblains' },

  { id:'chlamydia', title:'Chlamydia', category:'Infectious diseases', icon:'🦠',
    overview:'The commonest bacterial sexually transmitted infection in the UK, caused by Chlamydia trachomatis, and frequently asymptomatic. Untreated infection can cause pelvic inflammatory disease, infertility and ectopic pregnancy, so detection (including opportunistic screening), treatment and partner notification are key.',
    features:[
      'Often asymptomatic (especially in women) — a major reason for screening young, sexually active people',
      'Women: increased/altered vaginal discharge, post-coital or intermenstrual bleeding, dysuria, deep dyspareunia, and lower abdominal pain (suggesting PID)',
      'Men: urethral discharge, dysuria, and testicular pain (epididymo-orchitis)',
      'Complications: PID, tubal infertility, ectopic pregnancy, chronic pelvic pain, reactive arthritis, and (in neonates) conjunctivitis/pneumonia',
      'Rectal and pharyngeal infection occur with relevant exposure; lymphogranuloma venereum (LGV) is a more invasive serovar',
      'Diagnosis: nucleic acid amplification test (NAAT) — a vulvovaginal swab in women, first-void urine in men, and site-specific swabs as indicated'],
    management:[
      'Test sexually active under-25s opportunistically (National Chlamydia Screening Programme) and anyone with symptoms or risk factors',
      'Treat confirmed (or strongly suspected) infection with first-line doxycycline 100 mg twice daily for 7 days (azithromycin where doxycycline is contraindicated, e.g. pregnancy — use per current guidance)',
      'Advise abstaining from sex until the patient and partner(s) have completed treatment (and 7 days after single-dose regimens)',
      'Partner notification is essential — offer help via GUM/health adviser to trace and treat recent partners',
      'Test for other STIs (gonorrhoea, HIV, syphilis) and discuss safer sex and contraception',
      'Treat PID/epididymo-orchitis promptly with appropriate combination antibiotics if there are complications — do not wait for results if clinically indicated',
      'Arrange a test of cure where recommended (e.g. pregnancy, rectal infection, persistent symptoms) and re-test at 3 months given high reinfection rates',
      'In pregnancy, treat and arrange test of cure; consider neonatal implications'],
    referral:[
      'Complicated infection (PID, epididymo-orchitis, reactive arthritis) → treat promptly ± GUM/specialist input',
      'Suspected LGV, treatment failure, or complex partner notification → GUM/sexual-health service',
      'Pregnancy → treat per pregnancy-safe regimen with test of cure and neonatal awareness',
      'Safeguarding concerns (e.g. STI in a young person/child) → follow safeguarding procedures'],
    source:'BASHH / NICE CKS — Chlamydia (uncomplicated genital)' },

  { id:'cholecystitis', title:'Acute cholecystitis', category:'Gastroenterology', icon:'🔶',
    overview:'Acute inflammation of the gallbladder, almost always from a gallstone obstructing the cystic duct. It presents with persistent right-upper-quadrant pain and systemic upset, and is distinguished from uncomplicated biliary colic and from the more dangerous ascending cholangitis. It usually needs admission and, ultimately, cholecystectomy.',
    features:[
      'Constant, severe right-upper-quadrant or epigastric pain (lasting hours, unlike the shorter pain of biliary colic), often radiating to the right shoulder/back',
      'Fever, nausea/vomiting, and a positive Murphy’s sign (arrest of inspiration on RUQ palpation)',
      'Distinguish from: biliary colic (transient pain, no fever/inflammation), ascending cholangitis (Charcot’s triad — RUQ pain, fever, jaundice — a biliary emergency), and gallstone pancreatitis',
      'Jaundice suggests common-bile-duct obstruction/cholangitis rather than simple cholecystitis',
      'Risk factors: the classic "fat, female, forty, fertile", plus rapid weight loss, diabetes and haemolysis',
      'Investigations: raised inflammatory markers; ultrasound (gallstones, thick-walled gallbladder, pericholecystic fluid); LFTs to assess for duct obstruction'],
    management:[
      'Suspected acute cholecystitis usually needs admission for analgesia, IV fluids, antibiotics and assessment',
      'In primary care: assess severity, provide analgesia/antiemetics, and arrange urgent admission if systemically unwell or the diagnosis is acute cholecystitis/cholangitis',
      'Arrange ultrasound and LFTs; differentiate from cholangitis (jaundice + fever) and pancreatitis',
      'Definitive treatment is laparoscopic cholecystectomy — ideally early (within ~1 week) during the same admission for acute cholecystitis',
      'Ascending cholangitis is an emergency needing resuscitation, antibiotics and urgent biliary drainage (ERCP)',
      'For recurrent biliary colic without acute inflammation, refer electively for cholecystectomy and advise on low-fat diet meanwhile',
      'Manage gallstone pancreatitis per the pancreatitis pathway',
      'Provide safety-netting for fever, jaundice or worsening pain while awaiting assessment'],
    referral:[
      'Suspected acute cholecystitis → urgent surgical admission',
      'Suspected ascending cholangitis (RUQ pain + fever + jaundice) or biliary sepsis → emergency admission for resuscitation and urgent ERCP',
      'Gallstone pancreatitis → emergency admission (pancreatitis pathway)',
      'Symptomatic gallstones/biliary colic → elective surgical referral for cholecystectomy'],
    source:'NICE CG188 (Gallstone disease) / NICE CKS' },

  { id:'cholesteatoma', title:'Cholesteatoma', category:'ENT', icon:'👂',
    overview:'An abnormal collection of keratinising squamous epithelium in the middle ear/mastoid that progressively expands and erodes surrounding structures. Though not a cancer, it is locally destructive and can cause serious complications (hearing loss, facial palsy, intracranial infection), so a chronically discharging, smelly ear is an ENT red flag.',
    features:[
      'A chronically discharging ear with a persistent, offensive (foul-smelling) discharge that fails to settle with topical treatment',
      'Progressive conductive hearing loss in the affected ear',
      'Otoscopy: a retraction pocket, crust or whitish keratin debris in the attic/posterosuperior pars flaccida, often with granulation',
      'Complications from local erosion: facial nerve palsy, vertigo/sensorineural loss (labyrinthine fistula), and intracranial spread (meningitis, brain abscess, sinus thrombosis)',
      'Can be congenital (a white mass behind an intact drum in a child) or acquired (commoner)',
      'Diagnosis is clinical/otoscopic, confirmed and assessed by ENT with microscopy and CT/MRI imaging'],
    management:[
      'Have a high index of suspicion for a chronically discharging, smelly ear or persistent attic crust/retraction — refer to ENT',
      'Do not rely on repeated courses of topical antibiotics to "cure" it — cholesteatoma needs surgery',
      'Refer routinely to ENT for diagnosis (microsuction, imaging) and treatment',
      'Definitive treatment is surgical removal (mastoidectomy/tympanoplasty) to eradicate disease and create a safe, dry ear',
      'Manage hearing loss and arrange long-term follow-up, as recurrence/residual disease is possible',
      'Recognise and refer urgently any complication (facial palsy, severe vertigo, meningism)',
      'Provide aural care advice (keep the ear dry) while awaiting assessment',
      'Counsel that surgery aims primarily for a safe ear, with hearing improvement a secondary goal'],
    referral:[
      'Suspected cholesteatoma (chronic foul ear discharge, attic crust/retraction, progressive hearing loss) → ENT referral',
      'Facial nerve palsy, severe vertigo, or features of intracranial complication (severe headache, meningism, neurology) → emergency referral',
      'Confirmed cholesteatoma → ENT for surgery and follow-up',
      'Congenital cholesteatoma (white mass behind an intact drum in a child) → paediatric ENT'],
    source:'NICE CKS / ENT UK guidance' },

  { id:'cll', title:'Chronic lymphocytic leukaemia (CLL)', category:'Haematology', icon:'🩸',
    overview:'A slowly progressive malignancy of mature B lymphocytes, and the commonest leukaemia in adults — predominantly older people. Many are diagnosed incidentally on a routine FBC showing a lymphocytosis, and many never need treatment ("watch and wait"). The GP role is recognition, monitoring and supporting infection risk.',
    features:[
      'Often asymptomatic — found incidentally as a persistent mature lymphocytosis on FBC',
      'When symptomatic: painless lymphadenopathy, hepatosplenomegaly, fatigue, weight loss and night sweats',
      'Recurrent infections from immune dysfunction (hypogammaglobulinaemia) — a major cause of morbidity',
      'Autoimmune complications: autoimmune haemolytic anaemia and immune thrombocytopenia',
      'Richter’s transformation (rapid nodal enlargement, systemic symptoms) is an uncommon but serious progression to aggressive lymphoma',
      'Diagnosis: FBC and blood film (lymphocytosis, smear cells) confirmed by immunophenotyping (flow cytometry); staging by Binet/Rai'],
    management:[
      'Investigate a persistent unexplained lymphocytosis with a blood film and refer to haematology for immunophenotyping',
      'Many patients are managed by "watch and wait" — monitoring with no treatment until there is progressive/symptomatic disease, as early treatment does not improve survival',
      'Treatment (when indicated) is specialist: targeted agents (e.g. BTK inhibitors such as ibrutinib/acalabrutinib, BCL-2 inhibitor venetoclax ± anti-CD20 antibodies) have largely replaced chemoimmunotherapy',
      'Manage infection risk: ensure vaccinations (inactivated — e.g. influenza, pneumococcal, COVID-19; avoid live vaccines if immunocompromised), prompt treatment of infections, and consider immunoglobulin replacement for recurrent severe infections',
      'Monitor for and refer autoimmune cytopenias and any features of Richter’s transformation',
      'Provide patient information; "watch and wait" causes anxiety, so explain the rationale clearly',
      'Coordinate shared care and supportive/palliative care where appropriate',
      'Be alert to a rising lymphocyte count, new B symptoms, or rapidly enlarging nodes'],
    referral:[
      'Persistent unexplained lymphocytosis or features of leukaemia (lymphadenopathy, hepatosplenomegaly, unexplained fatigue, infections, bruising) → haematology; possible leukaemia warrants a very urgent FBC within 48 hours (NICE NG12)',
      'Suspected Richter’s transformation (rapid nodal growth, systemic symptoms) → urgent haematology',
      'Autoimmune haemolysis or thrombocytopenia → urgent haematology',
      'Recurrent severe infections → haematology (consider immunoglobulin replacement)'],
    source:'NICE NG12 / BSH CLL guidance' },

  { id:'cml', title:'Chronic myeloid leukaemia (CML)', category:'Haematology', icon:'🩸',
    overview:'A myeloproliferative malignancy driven by the BCR-ABL1 fusion gene (the Philadelphia chromosome). Its prognosis has been transformed by tyrosine kinase inhibitors, which now give many patients a near-normal life expectancy. It is often found on a routine FBC showing a markedly raised white-cell count.',
    features:[
      'Frequently detected incidentally on FBC: a high white-cell count with the full spectrum of maturing granulocytes (left shift), often with basophilia and thrombocytosis',
      'When symptomatic (chronic phase): fatigue, weight loss, night sweats, and abdominal fullness/early satiety from massive splenomegaly',
      'Splenomegaly is the classic sign; gout and bleeding/bruising can occur',
      'Hyperviscosity/very high counts can cause priapism, visual disturbance or thrombosis',
      'Disease evolves through chronic → accelerated → blast phase (the latter resembling acute leukaemia) if untreated',
      'Diagnosis: FBC/film, then bone marrow and detection of BCR-ABL1 / the Philadelphia chromosome (cytogenetics/molecular)'],
    management:[
      'Investigate an unexplained high white-cell count with a blood film and refer to haematology',
      'Treatment is specialist: tyrosine kinase inhibitors (e.g. imatinib, dasatinib, nilotinib) targeting BCR-ABL1 are the mainstay and produce deep, durable responses in chronic-phase disease',
      'Monitoring of molecular response (BCR-ABL1 transcript levels) guides therapy; some patients in sustained deep remission may attempt treatment-free remission under specialist supervision',
      'Support adherence to TKIs (crucial to outcome) and manage their side effects (e.g. cytopenias, fluid retention, GI effects, cardiovascular risk with some agents)',
      'Allogeneic stem-cell transplant is reserved for advanced-phase or TKI-resistant disease',
      'Ensure relevant vaccinations and prompt treatment of infections',
      'Provide patient information and psychological support; coordinate shared monitoring',
      'Be alert to features of disease progression (rising counts, new symptoms, blast transformation)'],
    referral:[
      'Unexplained leukocytosis or features suggesting leukaemia → haematology; possible leukaemia warrants a very urgent FBC within 48 hours (NICE NG12)',
      'Very high white-cell count with hyperviscosity (priapism, visual disturbance, thrombosis) → emergency haematology',
      'Suspected accelerated/blast-phase transformation → urgent haematology',
      'TKI intolerance/resistance → specialist review'],
    source:'NICE NG12 / BSH CML guidance' }

  );
})();
